    ########################################################
    # src/databricks/labs/community_connector/sources/shopify/shopify_utils.py
    ########################################################

    RETRIABLE_STATUS_CODES = {429, 500, 502, 503, 504}
    MAX_RETRIES = 5
    INITIAL_BACKOFF = 1.0  # seconds; doubled after each retry


    def request_with_retry(
        session: requests.Session,
        url: str,
        params: dict[str, str] | None = None,
    ) -> requests.Response:
        """Issue a GET with exponential backoff on retriable errors.

        Honors the ``Retry-After`` header when present (Shopify returns this
        on 429 with a value in seconds), otherwise doubles the backoff
        (1, 2, 4, 8, 16 s).
        """
        backoff = INITIAL_BACKOFF
        resp = None
        for attempt in range(MAX_RETRIES):
            resp = session.get(url, params=params, timeout=30)
            if resp.status_code not in RETRIABLE_STATUS_CODES:
                return resp

            if attempt < MAX_RETRIES - 1:
                retry_after = resp.headers.get("Retry-After")
                try:
                    wait = float(retry_after) if retry_after else backoff
                except (TypeError, ValueError):
                    wait = backoff
                time.sleep(wait)
                backoff *= 2

        return resp


    def api_get(
        session: requests.Session,
        url: str,
        params: dict[str, str] | None,
        label: str,
    ) -> tuple[dict[str, Any], requests.Response]:
        """GET a Shopify endpoint and return (json_body, response).

        Returns the response too so callers can extract the Link header for
        cursor pagination.

        Raises RuntimeError on non-200 status with a descriptive label.
        """
        response = request_with_retry(session, url, params)
        if response.status_code != 200:
            raise RuntimeError(
                f"Shopify API error for {label}: "
                f"{response.status_code} {response.text}"
            )
        return response.json(), response


    # --------------------------------------------------------------------------- #
    # Link-header cursor pagination
    # --------------------------------------------------------------------------- #

    # Shopify returns pagination cursors in the Link response header, e.g.:
    #   Link: <https://shop.myshopify.com/admin/api/2026-04/products.json
    #          ?page_info=hijgklmn&limit=50>; rel="next"
    # We extract the next-page URL (or just the page_info value) for the next call.
    _NEXT_LINK_RE = re.compile(r'<([^>]+)>;\s*rel="next"')


    def extract_next_link(response: requests.Response) -> str | None:
        """Return the next-page URL from a Shopify Link response header.

        Returns ``None`` when there is no next page (i.e. drained).
        """
        link = response.headers.get("Link")
        if not link:
            return None
        match = _NEXT_LINK_RE.search(link)
        return match.group(1) if match else None


    def nullify_empty(record: dict, *keys: str) -> None:
        """Replace missing or empty-dict nested structs with ``None``."""
        for key in keys:
            if key not in record or record[key] == {}:
                record[key] = None


    def paginate_get(
        session: requests.Session,
        initial_url: str,
        initial_params: dict[str, str] | None,
        label: str,
        response_key: str,
    ):
        """Yield records by following Shopify Link-header cursor pagination.

        Initial call uses *initial_url* + *initial_params*. Subsequent
        calls follow the next-page URL from the Link header verbatim
        (Shopify's docs are explicit: only ``limit`` and ``fields`` are
        permitted alongside a ``page_info`` cursor; all original filter
        params are encoded in the cursor itself).
        """
        url, params = initial_url, initial_params
        while url:
            data, response = api_get(session, url, params, label)
            yield from data.get(response_key, [])
            url = extract_next_link(response)
            # After the first page the cursor URL embeds all filter params,
            # so subsequent calls pass no params of their own.
            params = None


    ########################################################
    # src/databricks/labs/community_connector/sources/shopify/shopify.py
    ########################################################

    _LOG = logging.getLogger(__name__)

    DEFAULT_API_VERSION = "2026-04"


    def _parse_max_records(table_options: dict[str, str]) -> int | None:
        """Parse the optional ``max_records_per_batch`` admission-control cap.

        Returns ``None`` when unset or non-numeric (uncapped).
        """
        raw = table_options.get("max_records_per_batch")
        if raw is None:
            return None
        try:
            value = int(raw)
        except (TypeError, ValueError):
            return None
        return value if value > 0 else None


    class ShopifyLakeflowConnect(LakeflowConnect):
        """Shopify Admin REST API connector.

        Auth: Admin API access token (custom-app token, format ``shpat_...``).
        Pagination: Link-header cursor pagination (``page_info`` parameter).
        Versioning: API version pinned via the ``api_version`` connection
        option; defaults to the latest stable version supported by this
        connector.

        See ``shopify_api_doc.md`` for endpoint specifics, scope mapping,
        rate-limit behavior, and per-table edge cases.
        """

        def __init__(self, options: dict[str, str]) -> None:
            """Initialize the Shopify connector.

            Expected options:
                - shop: Shopify shop subdomain (e.g. ``"lakeflow-test-store"``)
                - access_token: Admin API access token
                - api_version: API version string (optional, default ``2026-04``)
            """
            shop = options.get("shop")
            access_token = options.get("access_token")
            api_version = options.get("api_version") or DEFAULT_API_VERSION

            if not shop:
                raise ValueError("Shopify connector requires 'shop'")
            if not access_token:
                raise ValueError("Shopify connector requires 'access_token'")

            self.shop = shop
            self.api_version = api_version
            self.base_url = (
                f"https://{shop}.myshopify.com/admin/api/{api_version}"
            )

            self._session = requests.Session()
            self._session.headers.update(
                {
                    "X-Shopify-Access-Token": access_token,
                    "Accept": "application/json",
                }
            )

            # Cap incremental cursors at init time so a single trigger only
            # drains data that existed when the connector started; later data
            # is picked up by the next trigger with a fresh _init_time.
            # This is the AvailableNow termination guard.
            self._init_time = (
                datetime.now(timezone.utc).strftime("%Y-%m-%dT%H:%M:%SZ")
            )

        # ------------------------------------------------------------------ #
        # Interface methods
        # ------------------------------------------------------------------ #

        def list_tables(self) -> list[str]:
            return SUPPORTED_TABLES

        def get_table_schema(
            self, table_name: str, table_options: dict[str, str]
        ) -> StructType:
            if table_name not in TABLE_SCHEMAS:
                raise ValueError(f"Unsupported table: {table_name!r}")
            return TABLE_SCHEMAS[table_name]

        def read_table_metadata(
            self, table_name: str, table_options: dict[str, str]
        ) -> dict:
            if table_name not in TABLE_METADATA:
                raise ValueError(f"Unsupported table: {table_name!r}")
            return TABLE_METADATA[table_name]

        def read_table(
            self,
            table_name: str,
            start_offset: dict,
            table_options: dict[str, str],
        ) -> tuple[Iterator[dict], dict]:
            dispatch = {
                "locations": self._read_locations,
                "customers": self._read_customers,
                "products": self._read_products,
                "orders": self._read_orders,
                "refunds": self._read_refunds,
                "fulfillments": self._read_fulfillments,
                "inventory_levels": self._read_inventory_levels,
            }
            handler = dispatch.get(table_name)
            if handler is None:
                raise ValueError(f"Unsupported table: {table_name!r}")
            return handler(start_offset, table_options)

        # ------------------------------------------------------------------ #
        # Table readers
        # ------------------------------------------------------------------ #

        def _read_locations(
            self, start_offset: dict, table_options: dict[str, str]
        ) -> tuple[Iterator[dict], dict]:
            """Read locations as a snapshot (no pagination, no incremental).

            Locations endpoint has no incremental filter and no cursor
            pagination — Shopify caps the response at the full set, which
            is small for almost all merchants. Snapshot ingestion is the
            right fit.
            """
            data, _ = api_get(
                self._session,
                f"{self.base_url}/locations.json",
                params=None,
                label="locations",
            )
            records: list[dict[str, Any]] = []
            for loc in data.get("locations", []):
                rec = dict(loc)
                rec["shop"] = self.shop
                records.append(rec)
            return iter(records), {}

        # -- CDC tables (customers, products, orders) ---------------------- #

        def _read_cdc_table(
            self,
            start_offset: dict,
            table_options: dict[str, str],
            table_name: str,
            response_key: str,
            extra_params: dict[str, str] | None = None,
        ) -> tuple[Iterator[dict], dict]:
            """Generic CDC reader using ``updated_at`` watermark.

            - Server-side filter via Shopify's ``updated_at_min`` (inclusive).
            - Client-side strict ``>`` dedup to make the boundary exclusive.
            - Cursor capped at ``self._init_time`` so AvailableNow terminates
              even on a busy store. Records edited after init time are picked
              up by the next trigger with a fresh ``_init_time``.
            - Admission control via ``max_records_per_batch`` table option.
              When set and reached mid-walk, returns a partial cursor at the
              last-emitted record's ``updated_at`` so the next microbatch
              resumes from there. Records are sorted ascending by
              ``updated_at`` server-side, so the cap point is well-defined.
            - Pagination via Link-header cursor (``page_info``) — see utils.
            """
            start_offset = start_offset or {}
            since: str | None = start_offset.get("updated_at")

            # If we've already drained up to init_time, return stable offset
            # so the framework terminates this microbatch.
            if since and since >= self._init_time:
                return iter([]), start_offset

            max_records = _parse_max_records(table_options)

            params: dict[str, str] = {
                "limit": "250",
                "order": "updated_at asc",  # ensures admission-cap boundary
            }
            if extra_params:
                params.update(extra_params)
            if since:
                params["updated_at_min"] = since
            # Cap server-side at init_time so the page never includes records
            # edited after the connector started.
            params["updated_at_max"] = self._init_time

            url = f"{self.base_url}/{table_name}.json"

            records: list[dict[str, Any]] = []
            max_seen: str | None = since
            cap_hit = False
            for raw in paginate_get(
                self._session, url, params, table_name, response_key
            ):
                rec_updated = raw.get("updated_at")
                # Strict `>` to make Shopify's inclusive filter exclusive.
                if since and rec_updated and rec_updated <= since:
                    continue
                # Defensive: drop anything past the init-time cap that may
                # have slipped through if the server ignored updated_at_max.
                if rec_updated and rec_updated > self._init_time:
                    continue
                rec = dict(raw)
                rec["shop"] = self.shop
                records.append(rec)
                if rec_updated and (
                    max_seen is None or rec_updated > max_seen
                ):
                    max_seen = rec_updated
                if max_records is not None and len(records) >= max_records:
                    cap_hit = True
                    break

            if cap_hit:
                # Resume from the last emitted record on the next call.
                return iter(records), {"updated_at": max_seen}

            # Window fully drained — advance to init_time so a follow-up
            # call with this offset terminates immediately via the early
            # exit above. Without this, drained-but-empty windows would keep
            # the offset at `since` forever and AvailableNow wouldn't see
            # forward progress between non-empty trigger windows.
            end_cursor = max_seen if max_seen and max_seen >= self._init_time else self._init_time
            return iter(records), {"updated_at": end_cursor}

        def _read_customers(
            self, start_offset: dict, table_options: dict[str, str]
        ) -> tuple[Iterator[dict], dict]:
            return self._read_cdc_table(
                start_offset,
                table_options,
                table_name="customers",
                response_key="customers",
            )

        def _read_products(
            self, start_offset: dict, table_options: dict[str, str]
        ) -> tuple[Iterator[dict], dict]:
            return self._read_cdc_table(
                start_offset,
                table_options,
                table_name="products",
                response_key="products",
            )

        def _read_orders(
            self, start_offset: dict, table_options: dict[str, str]
        ) -> tuple[Iterator[dict], dict]:
            # Default `status=any` so cancelled / closed orders are
            # included — Shopify's default of `status=open` would silently
            # drop them. See shopify_api_doc.md for the gotcha.
            return self._read_cdc_table(
                start_offset,
                table_options,
                table_name="orders",
                response_key="orders",
                extra_params={"status": "any"},
            )

        # -- Per-order child resources (refunds, fulfillments) ------------- #

        def _read_per_order_table(
            self,
            start_offset: dict,
            table_options: dict[str, str],
            sub_resource: str,
            cursor_field: str,
        ) -> tuple[Iterator[dict], dict]:
            """Read a per-order child resource using the parent-orders trick.

            Discovers candidate orders via the orders endpoint
            (``updated_at_min=watermark``, Shopify's order ``updated_at``
            advances when refunds/fulfillments are added), then fetches the
            sub-resource per order. Records are filtered client-side by
            ``cursor_field > watermark`` and capped at ``self._init_time``.

            Honors ``max_records_per_batch`` for admission control: when
            reached mid-walk, stops at the next order boundary and returns
            a partial cursor at the last-emitted record's cursor.
            """
            start_offset = start_offset or {}
            since: str | None = start_offset.get(cursor_field)

            # Already drained up to init_time — nothing to do.
            if since and since >= self._init_time:
                return iter([]), start_offset

            max_records = _parse_max_records(table_options)

            orders_params: dict[str, str] = {
                "limit": "250",
                "status": "any",
                # Cap the parent walk at init_time so we don't chase orders
                # that arrived after the connector started.
                "updated_at_max": self._init_time,
            }
            if since:
                orders_params["updated_at_min"] = since

            all_records: list[dict[str, Any]] = []
            max_seen: str | None = since
            cap_hit = False

            for order in paginate_get(
                self._session,
                f"{self.base_url}/orders.json",
                orders_params,
                f"{sub_resource}-discovery",
                "orders",
            ):
                order_id = order.get("id")
                if not order_id:
                    continue
                try:
                    data, _ = api_get(
                        self._session,
                        f"{self.base_url}/orders/{order_id}/{sub_resource}.json",
                        params=None,
                        label=sub_resource,
                    )
                except RuntimeError as exc:
                    # Skip individual orders that fail (e.g. permissions on a
                    # specific order) so the whole batch doesn't blow up.
                    _LOG.warning(
                        "Skipping %s for order %s: %s",
                        sub_resource, order_id, exc,
                    )
                    continue
                for item in data.get(sub_resource, []):
                    ts = item.get(cursor_field)
                    if since and ts and ts <= since:
                        continue
                    # Defensive: drop records past init_time cap.
                    if ts and ts > self._init_time:
                        continue
                    rec = dict(item)
                    rec["shop"] = self.shop
                    all_records.append(rec)
                    if ts and (max_seen is None or ts > max_seen):
                        max_seen = ts
                if max_records is not None and len(all_records) >= max_records:
                    cap_hit = True
                    break

            if cap_hit:
                return iter(all_records), {cursor_field: max_seen}

            # Window fully drained — advance to init_time so next call sees
            # `since >= self._init_time` and terminates immediately.
            end_cursor = (
                max_seen
                if max_seen and max_seen >= self._init_time
                else self._init_time
            )
            return iter(all_records), {cursor_field: end_cursor}

        def _read_refunds(
            self, start_offset: dict, table_options: dict[str, str]
        ) -> tuple[Iterator[dict], dict]:
            return self._read_per_order_table(
                start_offset,
                table_options,
                sub_resource="refunds",
                cursor_field="created_at",
            )

        def _read_fulfillments(
            self, start_offset: dict, table_options: dict[str, str]
        ) -> tuple[Iterator[dict], dict]:
            return self._read_per_order_table(
                start_offset,
                table_options,
                sub_resource="fulfillments",
                cursor_field="updated_at",
            )

        # -- Inventory ----------------------------------------------------- #

        def _read_inventory_levels(
            self, start_offset: dict, table_options: dict[str, str]
        ) -> tuple[Iterator[dict], dict]:
            """Read inventory levels across all locations.

            The /inventory_levels.json endpoint requires ``location_ids``
            or ``inventory_item_ids`` as a query param, so we first list
            locations and then iterate. The endpoint has no date filter,
            so we fetch all levels each run; the framework's CDC merge on
            the composite ``(inventory_item_id, location_id)`` PK handles
            deltas idempotently.

            Watermark is capped at ``self._init_time`` and advanced to it
            on every call. This guarantees AvailableNow termination even
            when stock is updated continuously: the trigger only ingests
            the snapshot that existed at connector init.

            Honors ``max_records_per_batch`` for admission control: when
            the cap is hit mid-walk we stop and emit the location ID we
            were on so the next microbatch resumes from there.
            """
            start_offset = start_offset or {}
            # Resume cursor: for in-flight microbatches we track which
            # location index we last finished. None = start from the top.
            resume_loc = start_offset.get("location_id")
            max_records = _parse_max_records(table_options)

            locs_data, _ = api_get(
                self._session,
                f"{self.base_url}/locations.json",
                params=None,
                label="locations",
            )
            active_locs = sorted(
                str(loc["id"])
                for loc in locs_data.get("locations", [])
                if loc.get("id") and loc.get("active")
            )

            # Find resume point if this is a continuation microbatch.
            try:
                start_idx = (
                    active_locs.index(resume_loc) if resume_loc else 0
                )
            except ValueError:
                start_idx = 0

            all_records: list[dict[str, Any]] = []
            last_loc: str | None = resume_loc
            cap_hit = False
            for loc_id in active_locs[start_idx:]:
                for level in paginate_get(
                    self._session,
                    f"{self.base_url}/inventory_levels.json",
                    {"limit": "250", "location_ids": loc_id},
                    "inventory_levels",
                    "inventory_levels",
                ):
                    rec = dict(level)
                    rec["shop"] = self.shop
                    all_records.append(rec)
                last_loc = loc_id
                if max_records is not None and len(all_records) >= max_records:
                    cap_hit = True
                    break

            if cap_hit:
                return iter(all_records), {"location_id": last_loc}

            # All locations drained — return a stable terminal offset that
            # signals "done for this trigger". Anchored to init_time so a
            # subsequent trigger with a fresh _init_time supersedes it.
            return iter(all_records), {"updated_at": self._init_time}


    ########################################################
    # src/databricks/labs/community_connector/sparkpds/lakeflow_datasource.py
    ########################################################

    LakeflowConnectImpl = ShopifyLakeflowConnect
    # Constant option or column names
    METADATA_TABLE = "_community_table_metadata"
    NAMESPACES_TABLE = "_community_namespaces"
    TABLES_TABLE = "_community_tables"
    VIRTUAL_TABLES = (METADATA_TABLE, NAMESPACES_TABLE, TABLES_TABLE)
    TABLE_NAME = "tableName"
    TABLE_NAME_LIST = "tableNameList"
    TABLE_CONFIGS = "tableConfigs"
    IS_DELETE_FLOW = "isDeleteFlow"
    NAMESPACE_PREFIX = "namespacePrefix"
    NAMESPACE = "namespace"


    def _decode_list_of_str_option(option_name: str, value: str | None) -> list[str] | None:
        """Decode and validate a JSON-encoded ``list[str]`` Spark option.

        Returns ``None`` if the option is absent; otherwise the parsed list.
        Raises ``ValueError`` with the offending value if the JSON is malformed
        or the decoded value is not a list of strings.
        """
        if value is None:
            return None
        try:
            decoded = json.loads(value)
        except json.JSONDecodeError as e:
            raise ValueError(
                f"option '{option_name}' must be a JSON-encoded list[str]; "
                f"got non-JSON value: {value!r}"
            ) from e
        if not isinstance(decoded, list) or not all(isinstance(s, str) for s in decoded):
            raise ValueError(
                f"option '{option_name}' must be a JSON-encoded list[str]; "
                f"got: {decoded!r}"
            )
        return decoded


    def _decode_dict_option(option_name: str, value: str | None) -> dict:
        """Decode and validate a JSON-encoded ``dict`` Spark option."""
        if value is None:
            return {}
        try:
            decoded = json.loads(value)
        except json.JSONDecodeError as e:
            raise ValueError(
                f"option '{option_name}' must be a JSON-encoded dict; "
                f"got non-JSON value: {value!r}"
            ) from e
        if not isinstance(decoded, dict):
            raise ValueError(
                f"option '{option_name}' must be a JSON-encoded dict; got: {decoded!r}"
            )
        return decoded


    # PySpark's DataSource API requires camelCase method names and inherits
    # semantics from the parent class, so per-method docstrings are redundant.
    # pylint: disable=invalid-name,missing-function-docstring
    class LakeflowStreamReader(SimpleDataSourceStreamReader, SupportsTriggerAvailableNow):
        """
        Implements a data source stream reader for Lakeflow Connect.
        Currently, only the simpleStreamReader is implemented, which uses a
        more generic protocol suitable for most data sources that support
        incremental loading.
        """

        def __init__(
            self,
            options: dict[str, str],
            schema: StructType,
            lakeflow_connect: LakeflowConnect,
        ):
            self.options = options
            self.lakeflow_connect = lakeflow_connect
            self.schema = schema

        def initialOffset(self):
            return {}

        def read(self, start: dict) -> (Iterator[tuple], dict):
            is_delete_flow = self.options.get(IS_DELETE_FLOW) == "true"
            # Strip delete flow options before passing to connector
            table_options = {
                k: v for k, v in self.options.items() if k != IS_DELETE_FLOW
            }

            if is_delete_flow:
                records, offset = self.lakeflow_connect.read_table_deletes(
                    self.options[TABLE_NAME], start, table_options
                )
            else:
                records, offset = self.lakeflow_connect.read_table(
                    self.options[TABLE_NAME], start, table_options
                )
            rows = map(lambda x: parse_value(x, self.schema), records)
            return rows, offset

        def readBetweenOffsets(self, start: dict, end: dict) -> Iterator[tuple]:
            # TODO: This does not ensure the records returned are identical across repeated calls.
            # For append-only tables, the data source must guarantee that reading from the same
            # start offset will always yield the same set of records.
            # For tables ingested as incremental CDC, it is only necessary that no new changes
            # are missed in the returned records.
            return self.read(start)[0]

        def prepareForTriggerAvailableNow(self) -> None:
            # No need to do anything special here. Everything is handled in the __init__ method.
            pass


    class LakeflowPartitionedStreamReader(DataSourceStreamReader, SupportsTriggerAvailableNow):
        """Proxy that bridges SupportsPartitionedStream to PySpark's DataSourceStreamReader.

        Used when a connector implements the SupportsPartitionedStream mixin to
        support partitioned streaming reads across Spark executors.
        """

        def __init__(
            self,
            options: dict[str, str],
            schema: StructType,
            lakeflow_connect: LakeflowConnect,
        ):
            self.options = options
            self.schema = schema
            self.lakeflow_connect = lakeflow_connect
            self.table_name = options[TABLE_NAME]
            self.table_options = {k: v for k, v in options.items() if k != IS_DELETE_FLOW}

        def initialOffset(self):
            return {}

        def getDefaultReadLimit(self):
            # Admission control is the connector's responsibility (e.g. via
            # window_days, max_records_per_batch), not the engine's.  Always
            # ask the engine for ReadAllAvailable.
            return ReadAllAvailable()

        def latestOffset(self, start: dict, limit) -> dict:
            # We declared ReadAllAvailable via getDefaultReadLimit; the engine
            # must respect it.  Anything else means admission-control expectations
            # we do not support — fail loudly rather than silently ignore.
            if not isinstance(limit, ReadAllAvailable):
                raise ValueError(
                    f"LakeflowPartitionedStreamReader only supports ReadAllAvailable; "
                    f"got {type(limit).__name__}. Micro-batch sizing must be controlled "
                    f"by the connector implementation (table_options), not the engine."
                )
            return self.lakeflow_connect.latest_offset(
                self.table_name, self.table_options, start
            )

        def partitions(self, start: dict, end: dict):
            partition_descs = self.lakeflow_connect.get_partitions(
                self.table_name, self.table_options, start, end
            )
            return [InputPartition(json.dumps(p)) for p in partition_descs]

        def read(self, partition: InputPartition):
            partition_desc = json.loads(partition.value)
            records = self.lakeflow_connect.read_partition(
                self.table_name, partition_desc, self.table_options
            )
            return map(lambda x: parse_value(x, self.schema), records)

        def prepareForTriggerAvailableNow(self) -> None:
            # No need to do anything special here. Everything is handled in the __init__ method.
            pass


    class LakeflowBatchReader(DataSourceReader):
        def __init__(
            self,
            options: dict[str, str],
            schema: StructType,
            lakeflow_connect: LakeflowConnect,
        ):
            self.options = options
            self.schema = schema
            self.lakeflow_connect = lakeflow_connect
            self.table_name = options[TABLE_NAME]
            self._supports_partition = isinstance(lakeflow_connect, SupportsPartition)

        def partitions(self):
            if self._supports_partition and self.table_name not in VIRTUAL_TABLES:
                try:
                    partition_descs = self.lakeflow_connect.get_partitions(
                        self.table_name, self.options
                    )
                    return [InputPartition(json.dumps(p)) for p in partition_descs]
                except Exception:
                    self._supports_partition = False
            return [InputPartition(None)]

        def read(self, partition):
            if self.table_name == METADATA_TABLE:
                records = self._read_table_metadata()
            elif self.table_name == NAMESPACES_TABLE:
                records = self._read_namespaces()
            elif self.table_name == TABLES_TABLE:
                records = self._read_tables()
            elif self._supports_partition and partition.value is not None:
                partition_desc = json.loads(partition.value)
                records = self.lakeflow_connect.read_partition(
                    self.table_name, partition_desc, self.options
                )
            else:
                records, _ = self.lakeflow_connect.read_table(self.table_name, None, self.options)
            return map(lambda x: parse_value(x, self.schema), records)

        def _read_table_metadata(self):
            table_names = _decode_list_of_str_option(
                TABLE_NAME_LIST, self.options.get(TABLE_NAME_LIST)
            ) or []
            table_configs = _decode_dict_option(
                TABLE_CONFIGS, self.options.get(TABLE_CONFIGS)
            )
            all_records = []
            # Preserve caller-supplied table order — caller controls it.
            for table in table_names:
                metadata = self.lakeflow_connect.read_table_metadata(
                    table, table_configs.get(table, {})
                )
                all_records.append({TABLE_NAME: table, **metadata})
            return all_records

        def _read_namespaces(self):
            # Connectors without SupportsNamespaces are flat — no rows.
            if not isinstance(self.lakeflow_connect, SupportsNamespaces):
                return []
            prefix = _decode_list_of_str_option(
                NAMESPACE_PREFIX, self.options.get(NAMESPACE_PREFIX)
            )
            namespaces = self.lakeflow_connect.list_namespaces(prefix)
            # Sort framework-side for deterministic output regardless of
            # connector iteration order.
            return [{"namespace": ns} for ns in sorted(namespaces)]

        def _read_tables(self):
            namespace_supplied = NAMESPACE in self.options
            if isinstance(self.lakeflow_connect, SupportsNamespaces):
                if not namespace_supplied:
                    raise ValueError(
                        f"option '{NAMESPACE}' is required when reading "
                        f"'{TABLES_TABLE}' against a connector that implements "
                        f"SupportsNamespaces. Pass a JSON-encoded list[str] "
                        f"(use '[]' for root-level tables; walk the tree via "
                        f"'{NAMESPACES_TABLE}' to enumerate every namespace)."
                    )
                namespace = _decode_list_of_str_option(
                    NAMESPACE, self.options[NAMESPACE]
                )
                tables = self.lakeflow_connect.list_tables_in_namespace(namespace)
                return [
                    {"namespace": namespace, TABLE_NAME: tn}
                    for tn in sorted(tables)
                ]
            # Flat connector path. Reject a stray `namespace` option — the
            # caller probably mistook this connector for namespace-aware and
            # silently ignoring the option would mask the bug.
            if namespace_supplied:
                raise ValueError(
                    f"option '{NAMESPACE}' was supplied but the connector does "
                    f"not implement SupportsNamespaces. Either omit the option "
                    f"or use a namespace-aware connector."
                )
            return [
                {"namespace": [], TABLE_NAME: tn}
                for tn in sorted(self.lakeflow_connect.list_tables())
            ]


    class LakeflowSource(DataSource):
        """
        PySpark DataSource base for Lakeflow Connect.

        Two ways the connector implementation is bound:

        - Per-source subclass (wheel / multi-file deployment): subclass and set
          ``_lakeflow_connect_cls``::

              class GmailDataSource(LakeflowSource):
                  _lakeflow_connect_cls = GmailLakeflowConnect

              spark.dataSource.register(GmailDataSource)

        - Merged single-file deployment (SDP): ``_lakeflow_connect_cls`` is left
          ``None`` and the connector is taken from the module-level
          ``LakeflowConnectImpl`` placeholder, which the merge script substitutes
          with the actual implementation class.
        """

        # Per-source subclasses set this. Left ``None`` on the base so the merged
        # single-file path falls back to the ``LakeflowConnectImpl`` placeholder.
        _lakeflow_connect_cls = None

        # Spark format name. Defaults to "lakeflow_connect" because Unity Catalog
        # connection-option injection looks for that exact string. A per-source
        # subclass may override this with its source name once it no longer relies
        # on UC injection (see the commented override in each source's __init__.py).
        _format_name = "lakeflow_connect"

        def __init__(self, options):
            self.options = options
            table = options.get(TABLE_NAME)
            # Catch typos against the framework's reserved virtual-table namespace
            # early — falling through to the connector with an unknown
            # `_community_*` name yields a confusing per-connector error.
            if table and table.startswith("_community_") and table not in VIRTUAL_TABLES:
                raise ValueError(
                    f"unknown framework virtual table '{table}'. Valid framework "
                    f"virtual tables are: {', '.join(VIRTUAL_TABLES)}. "
                    f"For a regular source table, use a name that does not start "
                    f"with '_community_'."
                )
            # Per-source subclasses bind the implementation via _lakeflow_connect_cls.
            # The merged single-file path leaves it None and relies on the
            # LakeflowConnectImpl placeholder (substituted by the merge script).
            connect_cls = type(self)._lakeflow_connect_cls or LakeflowConnectImpl
            self.lakeflow_connect = connect_cls(options)  # pylint: disable=abstract-class-instantiated

        @classmethod
        def name(cls):
            return cls._format_name

        def schema(self):
            table = self.options[TABLE_NAME]
            if table == METADATA_TABLE:
                return StructType(
                    [
                        StructField(TABLE_NAME, StringType(), False),
                        StructField("primary_keys", ArrayType(StringType()), True),
                        StructField("cursor_field", StringType(), True),
                        StructField("ingestion_type", StringType(), True),
                    ]
                )
            if table == NAMESPACES_TABLE:
                return StructType(
                    [
                        StructField("namespace", ArrayType(StringType()), False),
                    ]
                )
            if table == TABLES_TABLE:
                return StructType(
                    [
                        StructField("namespace", ArrayType(StringType()), False),
                        StructField(TABLE_NAME, StringType(), False),
                    ]
                )
            return self.lakeflow_connect.get_table_schema(table, self.options)

        def reader(self, schema: StructType):
            return LakeflowBatchReader(self.options, schema, self.lakeflow_connect)

        def streamReader(self, schema: StructType):
            # Use the partitioned DataSourceStreamReader when the connector
            # implements SupportsPartitionedStream and the table opts in.
            # Otherwise, delegate to super() which raises PySparkNotImplementedError,
            # causing Spark to fall back to simpleStreamReader().
            if isinstance(self.lakeflow_connect, SupportsPartitionedStream):
                table = self.options[TABLE_NAME]
                if self.lakeflow_connect.is_partitioned(table):
                    return LakeflowPartitionedStreamReader(self.options, schema, self.lakeflow_connect)
            return super().streamReader(schema)

        def simpleStreamReader(self, schema: StructType):
            return LakeflowStreamReader(self.options, schema, self.lakeflow_connect)


    spark.dataSource.register(LakeflowSource)
